      _node_args = {}
      unless opts.nil?
        _node_args['kill'] = opts.kill unless opts.kill.nil?
      end
      n = Service.new(self, @client, 'stop', _node_args)
      @client.invoke(n)
    end

    # Creates a tunnel that forwards traffic from the caller's network to this service.
    # @param opts - Optional arguments
